const AVOGADRO = 6.022e23;
const fmt = (value: number, digits = 3) => Number.isFinite(value) ? Number(value.toFixed(digits)).toLocaleString(undefined, { maximumFractionDigits: digits }) : "Invalid";
const sci = (value: number, digits = 3) => {
  if (!Number.isFinite(value)) return "Invalid";
  if (value === 0) return "0";
  if (Math.abs(value) >= 100000 || Math.abs(value) < 0.001) return value.toExponential(digits);
  return fmt(value, digits);
};
