function findElement(input: string) {
  const clean = input.trim().toLowerCase();
  const z = Number(clean);
  return ELEMENTS.find((element) => element.symbol.toLowerCase() === clean || element.name.toLowerCase() === clean || element.z === z) || ELEMENTS[5];
}

function parseFormula(formula: string) {
  const counts: Record<string, number> = {};
  const stack: Record<string, number>[] = [counts];
  const tokens = formula.match(/[A-Z][a-z]?|\d+|\(|\)/g) || [];
  for (let i = 0; i < tokens.length; i += 1) {
    const token = tokens[i];
    if (token === "(") {
      const group: Record<string, number> = {};
      stack.push(group);
      continue;
    }
    if (token === ")") {
      const group = stack.pop() || {};
      const multiplier = /^\d+$/.test(tokens[i + 1] || "") ? Number(tokens[++i]) : 1;
      const target = stack[stack.length - 1];
      Object.entries(group).forEach(([symbol, count]) => { target[symbol] = (target[symbol] || 0) + count * multiplier; });
      continue;
    }
    if (/^[A-Z][a-z]?$/.test(token)) {
      const multiplier = /^\d+$/.test(tokens[i + 1] || "") ? Number(tokens[++i]) : 1;
      const target = stack[stack.length - 1];
      target[token] = (target[token] || 0) + multiplier;
    }
  }
  return counts;
}

function shellConfig(z: number) {
  const capacities = [2, 8, 18, 32, 32, 18, 8];
  const shells: number[] = [];
  let remaining = z;
  capacities.forEach((capacity) => {
    if (remaining <= 0) return;
    const used = Math.min(capacity, remaining);
    shells.push(used);
    remaining -= used;
  });
  return shells.join(", ");
}

type Orbital = { label: string; n: number; type: "s" | "p" | "d" | "f"; electrons: number; max: number };
const ORBITALS: Array<[string, number, "s" | "p" | "d" | "f"]> = [
  ["1s", 2, "s"], ["2s", 2, "s"], ["2p", 6, "p"], ["3s", 2, "s"], ["3p", 6, "p"], ["4s", 2, "s"], ["3d", 10, "d"],
  ["4p", 6, "p"], ["5s", 2, "s"], ["4d", 10, "d"], ["5p", 6, "p"], ["6s", 2, "s"], ["4f", 14, "f"], ["5d", 10, "d"],
  ["6p", 6, "p"], ["7s", 2, "s"], ["5f", 14, "f"], ["6d", 10, "d"], ["7p", 6, "p"],
];
const NOBLE_GASES = [{ z: 2, symbol: "He" }, { z: 10, symbol: "Ne" }, { z: 18, symbol: "Ar" }, { z: 36, symbol: "Kr" }, { z: 54, symbol: "Xe" }, { z: 86, symbol: "Rn" }];
const CONFIG_EXCEPTIONS: Record<number, Record<string, number>> = {
  24: { "4s": 1, "3d": 5 },
  29: { "4s": 1, "3d": 10 },
  42: { "5s": 1, "4d": 5 },
  47: { "5s": 1, "4d": 10 },
  79: { "6s": 1, "4f": 14, "5d": 10 },
};

function electronConfigFor(z: number) {
  const occupancy: Orbital[] = [];
  let remaining = z;
  for (const [label, max, type] of ORBITALS) {
    if (remaining <= 0) break;
    const n = Number(label[0]);
    const electrons = Math.min(max, remaining);
    occupancy.push({ label, n, type, electrons, max });
    remaining -= electrons;
  }
  const exception = CONFIG_EXCEPTIONS[z];
  if (exception) {
    occupancy.forEach((orbital) => {
      if (exception[orbital.label] !== undefined) orbital.electrons = exception[orbital.label];
    });
  }
  return occupancy.filter((orbital) => orbital.electrons > 0);
}

function configText(orbitals: Orbital[]) {
  return orbitals.map((orbital) => `${orbital.label}${orbital.electrons}`).join(" ");
}

function nobleConfig(z: number) {
  const noble = [...NOBLE_GASES].reverse().find((gas) => gas.z < z);
  if (!noble) return configText(electronConfigFor(z));
  const remaining = electronConfigFor(z).filter((orbital) => orbital.n > Number(configText(electronConfigFor(noble.z)).match(/(\d)[spdf]/g)?.at(-1)?.[0] || 0) || orbital.label === "3d" || orbital.label === "4d" || orbital.label === "4f" || orbital.label === "5d" || orbital.label === "5f" || orbital.label === "6d");
  let skipped = noble.z;
  const tail: string[] = [];
  electronConfigFor(z).forEach((orbital) => {
    if (skipped >= orbital.electrons) skipped -= orbital.electrons;
    else {
      const electrons = orbital.electrons - skipped;
      skipped = 0;
      if (electrons > 0) tail.push(`${orbital.label}${electrons}`);
    }
  });
  return `[${noble.symbol}] ${tail.join(" ") || configText(remaining)}`.trim();
}

function valenceElectrons(z: number) {
  const orbitals = electronConfigFor(z);
  const outer = Math.max(...orbitals.map((orbital) => orbital.n));
  return orbitals.filter((orbital) => orbital.n === outer && (orbital.type === "s" || orbital.type === "p")).reduce((sum, orbital) => sum + orbital.electrons, 0);
}

function lastElectron(orbitals: Orbital[]) {
  const orbital = orbitals[orbitals.length - 1];
  const l = { s: 0, p: 1, d: 2, f: 3 }[orbital.type];
  const half = orbital.max / 2;
  const ml = Math.min(l, Math.max(-l, (orbital.electrons - 1) % (2 * l + 1) - l));
  const ms = orbital.electrons <= half ? "+1/2" : "-1/2";
  return `n=${orbital.n}, l=${l}, m_l=${ml}, m_s=${ms}`;
}

function orbitalDiagram(orbitals: Orbital[]) {
  return orbitals.slice(-5).map((orbital) => {
    const boxes = Math.ceil(orbital.max / 2);
    const arrows = Array.from({ length: boxes }, (_, index) => {
      const first = orbital.electrons > index ? "up" : "";
      const second = orbital.electrons > index + boxes ? "down" : "";
      return `[${first}${second ? "/" + second : ""}]`;
    }).join("");
    return `${orbital.label}: ${arrows}`;
  }).join(" | ");
}

function oxidationNumbers(formula: string, charge: number) {
  const counts = parseFormula(formula);
  const fixed: Record<string, number> = {};
  const groupOne = new Set(["Li", "Na", "K", "Rb", "Cs", "Fr"]);
  const groupTwo = new Set(["Be", "Mg", "Ca", "Sr", "Ba", "Ra"]);
  Object.keys(counts).forEach((symbol) => {
    if (groupOne.has(symbol) || symbol === "Ag") fixed[symbol] = 1;
    else if (groupTwo.has(symbol) || symbol === "Zn") fixed[symbol] = 2;
    else if (symbol === "Al") fixed[symbol] = 3;
    else if (symbol === "F") fixed[symbol] = -1;
    else if (symbol === "O") fixed[symbol] = formula.includes("O2") && formula.length <= 4 ? -1 : -2;
    else if (symbol === "H") fixed[symbol] = 1;
  });
  const unknown = Object.keys(counts).filter((symbol) => fixed[symbol] === undefined);
  if (Object.keys(counts).length === 1 && charge === 0) {
    fixed[Object.keys(counts)[0]] = 0;
  } else if (unknown.length === 1) {
    const knownTotal = Object.entries(fixed).reduce((sum, [symbol, ox]) => sum + ox * counts[symbol], 0);
    fixed[unknown[0]] = (charge - knownTotal) / counts[unknown[0]];
  }
  return Object.keys(counts).map((symbol) => ({ symbol, count: counts[symbol], oxidation: fixed[symbol] }));
}

function calculate(kind: Kind, values: Record<string, string>): Result {
  if (kind === "mole") {
    const mode = values.mode;
    const mass = num(values, "mass");
    const moles = num(values, "moles");
    const molarMass = num(values, "molarMass");
    if (mode === "mass") {
      const answer = moles * molarMass;
      return { label: "Mass", value: `${fmt(answer, 4)} g`, detail: "Solved from mass = moles x molar mass", step: `mass = n x M = ${moles} mol x ${molarMass} g/mol = ${fmt(answer, 4)} g.`, cards: [{ label: "Moles", value: `${fmt(moles)} mol` }, { label: "Molar mass", value: `${fmt(molarMass)} g/mol` }] };
    }
    if (mode === "molarMass") {
      const answer = mass / moles;
      return { label: "Molar mass", value: `${fmt(answer, 4)} g/mol`, detail: "Solved from molar mass = mass / moles", step: `M = m / n = ${mass} g / ${moles} mol = ${fmt(answer, 4)} g/mol.`, cards: [{ label: "Mass", value: `${fmt(mass)} g` }, { label: "Moles", value: `${fmt(moles)} mol` }] };
    }
    if (mode === "particles") {
      const particles = moles * AVOGADRO;
      return { label: "Particles", value: sci(particles), detail: "Atoms, molecules, ions, or formula units", step: `particles = moles x Avogadro number = ${moles} x 6.022 x 10^23 = ${sci(particles)} particles.`, cards: [{ label: "Avogadro number", value: "6.022 x 10^23" }, { label: "Moles", value: `${fmt(moles)} mol` }] };
    }
    const answer = mass / molarMass;
    return { label: "Moles", value: `${fmt(answer, 6)} mol`, detail: "Solved from n = m / M", step: `n = mass / molar mass = ${mass} g / ${molarMass} g/mol = ${fmt(answer, 6)} mol.`, cards: [{ label: "Mass", value: `${fmt(mass)} g` }, { label: "Particles", value: sci(answer * AVOGADRO) }] };
  }

  if (kind === "atom") {
    if (values.mode === "isotope") {
      const mass1 = num(values, "isotopeMass1");
      const abundance1 = num(values, "abundance1") / 100;
      const mass2 = num(values, "isotopeMass2");
      const abundance2 = num(values, "abundance2") / 100;
      const average = mass1 * abundance1 + mass2 * abundance2;
      return { label: "Average atomic mass", value: `${fmt(average, 5)} amu`, detail: "Weighted average of isotope masses", step: `average mass = (${mass1} x ${fmt(abundance1, 4)}) + (${mass2} x ${fmt(abundance2, 4)}) = ${fmt(average, 5)} amu.`, cards: [{ label: "Isotope 1", value: `${fmt(abundance1 * 100, 2)}%` }, { label: "Isotope 2", value: `${fmt(abundance2 * 100, 2)}%` }] };
    }
    const element = findElement(values.element);
    if (values.mode === "atomsFromMass") {
      const sampleMass = num(values, "sampleMass");
      const moles = sampleMass / element.mass;
      const atoms = moles * AVOGADRO;
      return { label: "Atoms in sample", value: sci(atoms), detail: `${element.name} sample converted through moles`, step: `moles = ${sampleMass} g / ${element.mass} g/mol = ${fmt(moles, 6)} mol. atoms = ${fmt(moles, 6)} x 6.022 x 10^23 = ${sci(atoms)} atoms.`, cards: [{ label: "Element", value: `${element.name} (${element.symbol})` }, { label: "Moles", value: `${fmt(moles, 6)} mol` }] };
    }
    const massNumber = Math.round(num(values, "massNumber") || Math.round(element.mass));
    const charge = num(values, "charge") || 0;
    const protons = element.z;
    const neutrons = massNumber - element.z;
    const electrons = element.z - charge;
    return { label: `${element.name} atom`, value: `${protons}p, ${neutrons}n, ${electrons}e`, detail: `Atomic number ${element.z}, mass number ${massNumber}`, step: `protons = atomic number = ${element.z}. neutrons = mass number - atomic number = ${massNumber} - ${element.z} = ${neutrons}. electrons = atomic number - charge = ${element.z} - (${charge}) = ${electrons}.`, cards: [{ label: "Shells", value: shellConfig(Math.max(0, electrons)) }, { label: "Period / group", value: `${element.period || "varies"} / ${element.group || "transition"}` }] };
  }

  if (kind === "electronConfiguration") {
    const element = findElement(values.element);
    const config = electronConfigFor(element.z);
    const full = configText(config);
    const short = nobleConfig(element.z);
    return { label: `${element.symbol} configuration`, value: full, detail: `${element.name}, atomic number ${element.z}`, step: `Aufbau filling order places ${element.z} electrons into the lowest-energy orbitals first. Full configuration: ${full}. Noble gas shorthand: ${short}.`, cards: [{ label: "Noble gas shorthand", value: short }, { label: "Valence electrons", value: `${valenceElectrons(element.z)}` }], extra: [`Orbital diagram: ${orbitalDiagram(config)}`, `Last electron quantum numbers: ${lastElectron(config)}`] };
  }

  const charge = num(values, "charge") || 0;
  if (values.mode === "redox") {
    const reactant = oxidationNumbers(values.reactantFormula, num(values, "reactantCharge") || 0).find((item) => item.symbol === values.redoxElement);
    const product = oxidationNumbers(values.productFormula, num(values, "productCharge") || 0).find((item) => item.symbol === values.redoxElement);
    const before = reactant?.oxidation ?? NaN;
    const after = product?.oxidation ?? NaN;
    const change = after - before;
    const process = change > 0 ? "oxidized" : change < 0 ? "reduced" : "unchanged";
    return { label: "Redox change", value: `${before} -> ${after}`, detail: `${values.redoxElement} is ${process}`, step: `Oxidation state changes from ${before} in ${values.reactantFormula} to ${after} in ${values.productFormula}. A rise means oxidation; a drop means reduction. Change = ${fmt(change, 3)}.`, cards: [{ label: "Process", value: process }, { label: "Electron change", value: `${Math.abs(change)} e- per atom` }] };
  }
  const states = oxidationNumbers(values.formula, charge);
  const readable = states.map((item) => `${item.symbol}: ${Number.isFinite(item.oxidation) ? fmt(item.oxidation, 3) : "unknown"}`).join(", ");
  return { label: "Oxidation states", value: readable, detail: `Charge balance for ${values.formula}`, step: `The calculator applies fixed rules first, then uses charge balance so the weighted sum equals ${charge}. Counts: ${states.map((item) => `${item.symbol}${item.count}`).join(", ")}.`, cards: states.map((item) => ({ label: item.symbol, value: Number.isFinite(item.oxidation) ? `${fmt(item.oxidation, 3)}` : "unknown" })) };
}

